mapper.select:
select dbo.lpad(isnull(max(rslt_ser), 0) + 1, 3, '0')
  from pd_insp_judg
 where cmpycd     = #{cmpycd}
   and insp_gb     = #{insp_gb}
   and insp_req_dt = #{insp_req_dt}
   and insp_req_no = #{insp_req_no}

mapper.insert:
insert into pd_insp_judg (
    cmpycd, insp_gb, insp_req_dt, insp_req_no, rslt_ser, prodid, linecd, progcd, ordymd, proymd, lotno,
    itemcd, rslt_cd, rslt_qty, bigo, addtime, updtime, updemp
) values (
    #{cmpycd}, #{insp_gb}, #{insp_req_dt}, #{insp_req_no}, #{rslt_ser}, #{prodid}, #{linecd}, #{progcd}, #{ordymd}, #{proymd}, #{lotno},
    #{itemcd}, #{rslt_cd}, #{rslt_qty}, #{bigo}, GETDATE(), GETDATE(), #{updemp}
)

mapper.update:
update pd_insp_judg
   set rslt_qty = #{rslt_qty},
       bigo     = #{bigo},
       updtime  = GETDATE(),
       updemp   = #{updemp}
 where cmpycd      = #{cmpycd}
   and insp_gb     = #{insp_gb}
   and insp_req_dt = #{insp_req_dt}
   and insp_req_no = #{insp_req_no}
   and rslt_ser    = #{rslt_ser}

mapper.delete:
delete from pd_insp_judg
 where cmpycd      = #{cmpycd}
   and insp_gb     = #{insp_gb}
   and insp_req_dt = #{insp_req_dt}
   and insp_req_no = #{insp_req_no}
    and rslt_ser = #{rslt_ser}
